('data-engineering-system-design-interviews', 'grp-interview-readiness', 3, 'topic', NULL, NULL, NULL, 'Data Engineering System Design Interviews', 'Explain ingestion, storage, processing, quality, orchestration, observability, security, and cost tradeoffs.', 'Data Engineering System Design Interviews is a concrete data engineering roadmap topic.', 'choice', 'grp-interview-readiness-topics', 2, 3, 6, 'advanced', 80, 540, 9820, '{"source": "roadmap.sh/data-engineer", "nodeKey": "data-engineering-system-design-interviews"}'::jsonb, true, true, '["Explain how Data Engineering System Design Interviews affects practical data engineering work.", "Apply Data Engineering System Design Interviews to build data pipeline components or evaluate an implementation decision.", "Identify common mistakes, trade-offs, and signals that the approach is working."]'::jsonb, '["Create concise notes or a diagram explaining Data Engineering System Design Interviews in context.", "Use the concept to produce a small applied example or decision note.", "Explain at least two trade-offs, risks, or debugging signals related to the topic."]'::jsonb),
('gate-final-review', 'ph-portfolio-career', 81, 'checkpoint', 'gate', NULL, NULL, 'Final Data Engineering Review Gate', 'Validate readiness after Portfolio, Interview Readiness, and Capstone by requiring evidence that the learner can validate data inputs, schemas, and quality expectations, trace data from source to output, and document assumptions and failure cases.', 'Final Data Engineering Review Gate verifies practical readiness for the next roadmap stage without changing the visual phase structure.', 'checkpoint', 'ph-portfolio-career-gates', 99, 81, 1, 'intermediate', 85, 300, 10030, '{"checkpoint": true, "source": "roadmap.sh/data-engineer", "nodeKey": "gate-final-review"}'::jsonb, true, true, '["Explain the key decisions, trade-offs, and risks from Portfolio, Interview Readiness, and Capstone.", "Apply the phase knowledge to a realistic data engineering scenario or artifact.", "Identify gaps, failure modes, or review items before moving to the next phase."]'::jsonb, '["Validate data inputs, schemas, and quality expectations.", "Trace data from source to output.", "Document assumptions and failure cases.", "Present completed projects with clear evidence.", "Capture the result as notes, code, diagrams, tests, screenshots, reports, or another reviewable artifact."]'::jsonb),
('proj-capstone-data-platform', 'ph-portfolio-career', 91, 'project', NULL, NULL, NULL, 'Required Data Engineering Capstone Project', 'Build a production-style data platform: ingestion, storage, orchestration, transformation, quality tests, warehouse/lakehouse tables, observability, docs, and deployment notes.', 'Project nodes are practice-heavy. Mini-projects are optional; milestone projects are required.', 'checkpoint', 'ph-portfolio-career-projects', 100, 91, 16, 'advanced', 75, 700, 10060, '{"project": true, "optionalPractice": false, "source": "roadmap.sh/data-engineer", "nodeKey": "proj-capstone-data-platform"}'::jsonb, true, true, '["Build Required Data Engineering Capstone Project", "Produce portfolio-ready evidence"]'::jsonb, '["Working pipeline or design exists", "README explains setup and tradeoffs", "Core behavior is tested or manually verified"]'::jsonb),
('proj-portfolio-package', 'ph-portfolio-career', 92, 'project', NULL, NULL, NULL, 'Required Portfolio Final Package', 'Polish the capstone with README, diagrams, runbook, data model docs, screenshots, sample queries, and known tradeoffs.', 'Project nodes are practice-heavy. Mini-projects are optional; milestone projects are required.', 'checkpoint', 'ph-portfolio-career-projects', 100, 92, 4, 'intermediate', 75, 700, 10140, '{"project": true, "optionalPractice": false, "source": "roadmap.sh/data-engineer", "nodeKey": "proj-portfolio-package"}'::jsonb, true, true, '["Build Required Portfolio Final Package", "Produce portfolio-ready evidence"]'::jsonb, '["Working pipeline or design exists", "README explains setup and tradeoffs", "Core behavior is tested or manually verified"]'::jsonb);
